// ACTIVE BUZZER
#define BUZZER 8
void setup() { pinMode(BUZZER, OUTPUT); }
void loop() {
  digitalWrite(BUZZER, HIGH); // Sound ON
  delay(500);
  digitalWrite(BUZZER, LOW);  // Sound OFF
  delay(500);
}

